class AuthProvider extends ChangeNotifier {
  final AuthManager _authManager = AuthManager();
  bool _isAuthenticated = false;
  Map<String, dynamic>? _userData;

  bool get isAuthenticated => _isAuthenticated;
  Map<String, dynamic>? get userData => _userData;

  Future<void> initialize() async {
    await _authManager.initialize();
    await checkAuthStatus();
  }

  Future<void> checkAuthStatus() async {
    _isAuthenticated = await _authManager.isLoggedIn();
    if (_isAuthenticated) {
      _userData = await _authManager.getUserData();
    }
    notifyListeners();
  }

  Future<bool> login({
    required String accessToken,
    required String refreshToken,
    required Map<String, dynamic> userData,
    int? expiresInSeconds,
  }) async {
    final success = await _authManager.login(
      accessToken: accessToken,
      refreshToken: refreshToken,
      userData: userData,
      expiresInSeconds: expiresInSeconds,
    );

    if (success) {
      _isAuthenticated = true;
      _userData = userData;
      notifyListeners();
    }

    return success;
  }

  Future<bool> logout() async {
    final success = await _authManager.logout();

    if (success) {
      _isAuthenticated = false;
      _userData = null;
      notifyListeners();
    }

    return success;
  }

  Future<String?> getAccessToken() async {
    return await _authManager.getAccessToken();
  }

  Future<String?> getRefreshToken() async {
    return await _authManager.getRefreshToken();
  }

  Future<bool> updateAccessToken(String newAccessToken, {int? expiresInSeconds}) async {
    return await _authManager.updateAccessToken(
      newAccessToken,
      expiresInSeconds: expiresInSeconds,
    );
  }

  Future<bool> updateUserData(Map<String, dynamic> userData) async {
    final success = await _authManager.updateUserData(userData);
    if (success) {
      _userData = userData;
      notifyListeners();
    }
    return success;
  }
}

